    if not _non_empty_string(row.get("text")):
        _add_error(
            errors,
            "SOURCE_TEXT_EMPTY",
            f"{path}.text",
            "Source text must be non-empty.",
        )

    for string_path, string_value in _string_values(row, path):
        if _has_sensitive_text(string_value):
            _add_error(
